settings.custom_liquid:
{% if product.selected_or_first_available_variant.available and product.selected_or_first_available_variant.inventory_management == 'shopify' %}
  {% assign inventory = product.selected_or_first_available_variant.inventory_quantity %}
  {% if inventory > 0 %}
    <p style="font-weight: 500; color: #d00; font-size: 16px;">
      Limited quantity! 🔥 only {{ inventory }} pieces left in stock
    </p>
  {% endif %}
{% endif %}
